const aiResponse = $input.item.json.text || $input.item.json.output || '';
const llmError = (() => {
  const raw = $input.item.json.error;
  if (!raw) return '';
  if (typeof raw === 'string') return raw;
  return (raw.message || raw.description || JSON.stringify(raw)).toString();
})();
const context = $('Ensure New Reviews').item.json || {};
const sourceReviews = Array.isArray(context.reviews) ? context.reviews : [];

if (sourceReviews.length === 0) {
  return [];
}

const normalizeJsonString = (rawValue) => {
  const sanitized = (rawValue || '')
    .toString()
    .trim()
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/g, '')
    .trim();

  if (!sanitized) {
    return '';
  }

  const arrayStart = sanitized.indexOf('[');
  const arrayEnd = sanitized.lastIndexOf(']');
  if (arrayStart !== -1 && arrayEnd !== -1 && arrayEnd > arrayStart) {
    return sanitized.slice(arrayStart, arrayEnd + 1);
  }

  return sanitized;
};

let parsedData = [];
try {
  const jsonString = normalizeJsonString(aiResponse);
  parsedData = JSON.parse(jsonString);

  if (!Array.isArray(parsedData)) {
    parsedData = [parsedData];
  }
} catch (error) {
  console.error('JSON 파싱 실패:', error);
  parsedData = [];
}

if (!parsedData.length) {
  return [{
    json: {
      ID: `PARSE_ERROR_${Date.now()}`,
      긴급도: 'ERROR',
      유형: '파싱실패',
      요약: llmError ? `LLM error: ${llmError}` : 'No valid data parsed',
      원본: aiResponse.toString().slice(0, 1500),
      별점: '',
      작성자: 'system',
      작성일시: new Date().toISOString(),
      runId: context.runId || `RUN_${Date.now()}`,
      jobId: context.jobId || null,
      appStoreId: context.appStoreId || null,
      country: context.country || null,
      appName: context.appName || '',
    },
  }];
}

return sourceReviews.map((review, index) => {
  const item = parsedData[index] || {};

  const originalAuthor = (review.author || '').toString();
  const originalDate = (review.reviewedAt || new Date().toISOString()).toString();
  const originalRating = (review.rating ?? '').toString();
  const originalContent = (review.content || '').toString();
  const originalId = (review.reviewId || '').toString();

  return {
    json: {
      priority: item.priority || '✅ Normal',
      category: item.category || '기타',
      summary: item.summary || '분류 결과 없음',
      author: originalAuthor,
      date: originalDate,
      rating: originalRating,
      content: originalContent,
      id: originalId,
      ID: originalId,
      긴급도: item.priority || '✅ Normal',
      유형: item.category || '기타',
      요약: item.summary || '분류 결과 없음',
      작성자: originalAuthor,
      작성일시: originalDate,
      별점: originalRating,
      원본: originalContent,
      runId: context.runId || `RUN_${Date.now()}`,
      jobId: context.jobId || null,
      appStoreId: context.appStoreId || null,
      country: context.country || null,
      appName: context.appName || '',
    },
  };
});

const normalizeValue = (value) => (value ?? '').toString().trim();

const context = (() => {
  try {
    return $('Prepare Run Context').item.json || {};
  } catch {
    return {};
  }
})();

const currentItems = $input.all();
if (!Array.isArray(currentItems) || currentItems.length === 0) {
  return [];
}

const seenCurrentIds = new Set();
const output = [];

for (const item of currentItems) {
  const row = item.json || {};
  const id = normalizeValue(row.id || row.ID);

  if (!id || seenCurrentIds.has(id)) {
    continue;
  }

  seenCurrentIds.add(id);

  const priority = row.priority || row.긴급도 || '';
  const category = row.category || row.유형 || '';
  const summary = row.summary || row.요약 || '';
  const content = row.content || row.원본 || '';
  const rating = row.rating || row.별점 || '';
  const author = row.author || row.작성자 || '';
  const date = row.date || row.작성일시 || '';

  output.push({
    json: {
      ID: id,
      긴급도: priority,
      유형: category,
      요약: summary,
      원본: content,
      별점: rating,
      작성자: author,
      작성일시: date,
      priority,
      category,
      summary,
      content,
      rating,
      author,
      date,
      runId: row.runId || context.runId || null,
      jobId: row.jobId || context.jobId || null,
      appStoreId: row.appStoreId || context.appStoreId || null,
      country: row.country || context.country || null,
      appName: row.appName || context.appName || null,
    }
  });
}

return output;

const inputItems = $input.all();
if (!Array.isArray(inputItems) || inputItems.length === 0) {
  return [];
}

const context = inputItems[0]?.json || {};
const appStoreId = (context.appStoreId || '').toString().trim();
const country = (context.country || 'kr').toString().trim().toLowerCase();
const appName = (context.appName || '').toString().trim();
const runId = (context.runId || `RUN_${Date.now()}`).toString();
const jobId = (context.jobId || '').toString().trim() || null;

if (!appStoreId) {
  throw new Error('Prepare Upsert Payload missing appStoreId');
}

const normalizePriority = (value) => {
  const normalized = (value ?? '')
    .toString()
    .replace(/[🚨⚠️✅]/g, '')
    .trim()
    .toLowerCase();

  if (normalized.includes('critical')) {
    return 'Critical';
  }
  if (normalized.includes('high')) {
    return 'High';
  }
  return 'Normal';
};

const reviews = inputItems.map(({ json = {} }) => ({
  reviewId: (json.ID || json.id || '').toString().trim(),
  rating: Number((json.rating || json.별점 || '0').toString().trim()) || 0,
  author: (json.author || json.작성자 || '').toString().trim(),
  content: (json.content || json.원본 || '').toString().trim(),
  reviewedAt: (json.date || json.작성일시 || new Date().toISOString()).toString(),
  priority: normalizePriority(json.priority || json.긴급도),
  category: (json.category || json.유형 || '기타').toString().trim(),
  summary: (json.summary || json.요약 || '분류 결과 없음').toString().trim(),
  modelVersion: ($env.VOC_MODEL_VERSION || 'gemini').toString(),
  rawSource: {
    id: json.ID || json.id,
    content: json.content || json.원본,
    author: json.author || json.작성자,
    rating: json.rating || json.별점,
    date: json.date || json.작성일시,
  },
})).filter((review) => review.reviewId && review.rating > 0);

if (reviews.length === 0) {
  return [];
}

return [{
  json: {
    runId,
    jobId,
    payload: {
      runId,
      jobId,
      source: 'n8n',
      app: {
        appStoreId,
        country,
        appName,
      },
      reviews,
    },
  },
}];

const payload = $json.payload;
if (!payload) {
  return [];
}

const token = ($env.PIPELINE_WEBHOOK_SECRET || '').toString().trim();
if (!token) {
  throw new Error('PIPELINE_WEBHOOK_SECRET is required');
}

const timestamp = Date.now().toString();

return [{
  json: {
    payload,
    runId: $json.runId || payload.runId || null,
    timestamp,
    token,
  }
}];

const upsertContext = $('Prepare Upsert Payload').item.json || {};
const payload = upsertContext.payload || {};

const runId = ($json.runId || upsertContext.runId || `RUN_${Date.now()}`).toString();
const appStoreId = (payload.app?.appStoreId || '').toString().trim();
const country = (payload.app?.country || 'kr').toString().trim().toLowerCase();
const jobId = (upsertContext.jobId || payload.jobId || '').toString().trim() || null;

if (!appStoreId) {
